import React, { useState, useEffect, useMemo } from 'react';
import { Header } from './components/Header';
import { Hero } from './components/Hero';
import { CategoryFilter } from './components/CategoryFilter';
import { AppCard } from './components/AppCard';
import { ToolDetailModal } from './components/ToolDetailModal';
import { Footer } from './components/Footer';
import { TOOLS_DATA } from './data/mockData';
import { Category, AiTool } from './types';

function App() {
  const [isDark, setIsDark] = useState(true);
  const [selectedCategory, setSelectedCategory] = useState<Category>(Category.ALL);
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedTool, setSelectedTool] = useState<AiTool | null>(null);

  useEffect(() => {
    // Check local storage or system preference
    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
      setIsDark(true);
    } else {
      document.documentElement.classList.remove('dark');
      setIsDark(false);
    }
  }, []);

  const toggleTheme = () => {
    const html = document.documentElement;
    if (html.classList.contains('dark')) {
      html.classList.remove('dark');
      localStorage.setItem('theme', 'light');
      setIsDark(false);
    } else {
      html.classList.add('dark');
      localStorage.setItem('theme', 'dark');
      setIsDark(true);
    }
  };

  const filteredTools = useMemo(() => {
    return TOOLS_DATA.filter((tool) => {
      const matchesCategory = selectedCategory === Category.ALL || tool.category === selectedCategory;
      const searchLower = searchTerm.toLowerCase();
      const matchesSearch = 
        tool.name.toLowerCase().includes(searchLower) ||
        tool.description.toLowerCase().includes(searchLower) ||
        tool.tags.some(tag => tag.toLowerCase().includes(searchLower));

      return matchesCategory && matchesSearch;
    });
  }, [selectedCategory, searchTerm]);

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50 text-slate-900 dark:bg-[#0f172a] dark:text-[#f8fafc] transition-colors duration-300">
      <Header toggleTheme={toggleTheme} isDark={isDark} />

      <main className="flex-1">
        <Hero searchTerm={searchTerm} setSearchTerm={setSearchTerm} />

        <CategoryFilter 
          selectedCategory={selectedCategory} 
          setSelectedCategory={setSelectedCategory} 
        />

        <div id="directory" className="max-w-7xl mx-auto px-6 py-12">

          {/* Results Count */}
          <div className="mb-8 flex items-center justify-between">
            <h2 className="text-2xl font-display font-bold text-slate-900 dark:text-white">
              {selectedCategory === Category.ALL ? 'All Tools' : selectedCategory}
              <span className="ml-3 text-sm font-sans font-normal text-slate-500 bg-slate-200 dark:bg-white/10 px-2 py-1 rounded-full">
                {filteredTools.length}
              </span>
            </h2>

            <div className="hidden sm:flex items-center gap-2 text-sm text-slate-500">
                <span>Sort by:</span>
                <select className="bg-transparent border-none outline-none font-bold text-brand-primary cursor-pointer">
                    <option>Popularity</option>
                    <option>Newest</option>
                    <option>Rating</option>
                </select>
            </div>
          </div>

          {/* Grid */}
          {filteredTools.length > 0 ? (
            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-8">
              {filteredTools.map((tool) => (
                <AppCard 
                  key={tool.id} 
                  tool={tool} 
                  onClick={setSelectedTool} 
                />
              ))}
            </div>
          ) : (
            <div className="text-center py-20">
                <div className="inline-flex justify-center items-center w-20 h-20 rounded-full bg-slate-200 dark:bg-white/5 mb-6 text-4xl text-slate-400">
                    <i className="fa-regular fa-folder-open"></i>
                </div>
                <h3 className="text-xl font-bold mb-2">No tools found</h3>
                <p className="text-slate-500">Try adjusting your search or category filter.</p>
                <button 
                    onClick={() => {setSearchTerm(''); setSelectedCategory(Category.ALL)}}
                    className="mt-6 text-brand-primary hover:underline font-medium"
                >
                    Clear all filters
                </button>
            </div>
          )}
        </div>
      </main>

      <Footer />

      {/* Modal */}
      {selectedTool && (
        <ToolDetailModal 
          tool={selectedTool} 
          onClose={() => setSelectedTool(null)} 
        />
      )}
    </div>
  );
}

export default App;

