{
  "name": "vibelab-server",
  "version": "1.0.0",
  "main": "index.js",
  "scripts": {
    "start": "node index.js"
  },
  "dependencies": {
    "express": "^4.18.2",
    "cors": "^2.8.5",
    "better-sqlite3": "^9.4.3"
  }
}

const express = require('express');
const cors = require('cors');
const Database = require('better-sqlite3');
const path = require('path');
const fs = require('fs');

const app = express();
const PORT = 3000;
const ADMIN_KEY = process.env.ADMIN_KEY || 'vibelab_secret';

// Middleware
app.use(cors());
app.use(express.json());

// Database Setup
const dataDir = path.join(__dirname, 'data');
if (!fs.existsSync(dataDir)) {
    fs.mkdirSync(dataDir);
}
const db = new Database(path.join(dataDir, 'tools.db'));

// Initialize Schema
db.exec(`
    CREATE TABLE IF NOT EXISTS tools (
        id TEXT PRIMARY KEY,
        name TEXT NOT NULL,
        shortDescription TEXT,
        description TEXT,
        category TEXT,
        rating REAL,
        reviewCount INTEGER,
        pricing TEXT,
        imageUrl TEXT,
        tags TEXT,
        websiteUrl TEXT,
        featured INTEGER DEFAULT 0,
        createdAt DATETIME DEFAULT CURRENT_TIMESTAMP
    )
`);

// Seed Data if empty
const count = db.prepare('SELECT count(*) as count FROM tools').get();
if (count.count === 0) {
    console.log('Seeding database...');
    const seedData = [
        {
            id: '1',
            name: 'Gemini',
            shortDescription: "Google's most capable AI model.",
            description: 'Gemini is built from the ground up for multimodality — reasoning seamlessly across text, images, video, audio, and code.',
            category: 'Text & Writing',
            rating: 4.9,
            reviewCount: 1240,
            pricing: 'Freemium',
            imageUrl: 'https://picsum.photos/400/300?random=1',
            tags: JSON.stringify(['Google', 'LLM', 'Multimodal']),
            websiteUrl: 'https://gemini.google.com',
            featured: 1
        },
        {
            id: '2',
            name: 'Midjourney',
            shortDescription: 'Hyper-realistic image generation.',
            description: 'Midjourney is an independent research lab exploring new mediums of thought and expanding the imaginative powers of the human species.',
            category: 'Image Generation',
            rating: 4.8,
            reviewCount: 856,
            pricing: 'Paid',
            imageUrl: 'https://picsum.photos/400/300?random=2',
            tags: JSON.stringify(['Art', 'Design', 'Discord']),
            websiteUrl: 'https://midjourney.com',
            featured: 1
        }
        // ... (Keep minimal seed to save space, user can add more via Admin)
    ];

    const insert = db.prepare(`
        INSERT INTO tools (id, name, shortDescription, description, category, rating, reviewCount, pricing, imageUrl, tags, websiteUrl, featured)
        VALUES (@id, @name, @shortDescription, @description, @category, @rating, @reviewCount, @pricing, @imageUrl, @tags, @websiteUrl, @featured)
    `);

    const transaction = db.transaction((tools) => {
        for (const tool of tools) insert.run(tool);
    });
    transaction(seedData);
}

// Helper: Auth Middleware
const requireAuth = (req, res, next) => {
    const key = req.headers['x-admin-key'];
    if (key !== ADMIN_KEY) {
        return res.status(403).json({ error: 'Unauthorized' });
    }
    next();
};

// Routes

// GET All Tools
app.get('/api/tools', (req, res) => {
    try {
        const tools = db.prepare('SELECT * FROM tools ORDER BY featured DESC, rating DESC').all();
        // Parse tags back to array
        const parsedTools = tools.map(t => ({
            ...t,
            tags: JSON.parse(t.tags),
            featured: Boolean(t.featured)
        }));
        res.json(parsedTools);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// GET One Tool
app.get('/api/tools/:id', (req, res) => {
    try {
        const tool = db.prepare('SELECT * FROM tools WHERE id = ?').get(req.params.id);
        if (!tool) return res.status(404).json({ error: 'Tool not found' });

        tool.tags = JSON.parse(tool.tags);
        tool.featured = Boolean(tool.featured);
        res.json(tool);
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// POST Create Tool (Protected)
app.post('/api/tools', requireAuth, (req, res) => {
    try {
        const tool = req.body;
        const id = Date.now().toString(); // Simple ID generation

        const insert = db.prepare(`
            INSERT INTO tools (id, name, shortDescription, description, category, rating, reviewCount, pricing, imageUrl, tags, websiteUrl, featured)
            VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
        `);

        insert.run(
            id,
            tool.name,
            tool.shortDescription,
            tool.description,
            tool.category,
            tool.rating || 0,
            tool.reviewCount || 0,
            tool.pricing,
            tool.imageUrl,
            JSON.stringify(tool.tags || []),
            tool.websiteUrl,
            tool.featured ? 1 : 0
        );

        res.status(201).json({ id, ...tool });
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: error.message });
    }
});

// PUT Update Tool (Protected)
app.put('/api/tools/:id', requireAuth, (req, res) => {
    try {
        const tool = req.body;
        const { id } = req.params;

        const update = db.prepare(`
            UPDATE tools SET 
                name = ?, shortDescription = ?, description = ?, category = ?, 
                rating = ?, reviewCount = ?, pricing = ?, imageUrl = ?, 
                tags = ?, websiteUrl = ?, featured = ?
            WHERE id = ?
        `);

        const info = update.run(
            tool.name,
            tool.shortDescription,
            tool.description,
            tool.category,
            tool.rating,
            tool.reviewCount,
            tool.pricing,
            tool.imageUrl,
            JSON.stringify(tool.tags || []),
            tool.websiteUrl,
            tool.featured ? 1 : 0,
            id
        );

        if (info.changes === 0) return res.status(404).json({ error: 'Tool not found' });
        res.json({ id, ...tool });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// DELETE Tool (Protected)
app.delete('/api/tools/:id', requireAuth, (req, res) => {
    try {
        const info = db.prepare('DELETE FROM tools WHERE id = ?').run(req.params.id);
        if (info.changes === 0) return res.status(404).json({ error: 'Tool not found' });
        res.json({ message: 'Deleted successfully' });
    } catch (error) {
        res.status(500).json({ error: error.message });
    }
});

// Verify Admin Key
app.post('/api/auth/verify', (req, res) => {
    const { key } = req.body;
    if (key === ADMIN_KEY) {
        res.json({ valid: true });
    } else {
        res.status(401).json({ valid: false });
    }
});

app.listen(PORT, () => {
    console.log(`Server running on port ${PORT}`);
});

server {
