import React, { useState, useEffect } from 'react';
import { AiTool, Category } from '../types';
import { api } from '../utils/api';

const DEFAULT_TOOL: Partial<AiTool> = {
  name: '',
  category: Category.TEXT,
  description: '',
  shortDescription: '',
  pricing: 'Freemium',
  imageUrl: 'https://picsum.photos/400/300',
  websiteUrl: '',
  tags: [],
  rating: 0,
  reviewCount: 0,
  featured: false
};

export const Admin: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [key, setKey] = useState('');
  const [tools, setTools] = useState<AiTool[]>([]);
  const [editingTool, setEditingTool] = useState<Partial<AiTool> | null>(null);
  const [loading, setLoading] = useState(false);

  useEffect(() => {
    const savedKey = localStorage.getItem('vibelab_admin_key');
    if (savedKey) {
        verify(savedKey);
    }
  }, []);

  const verify = async (k: string) => {
      const valid = await api.verifyKey(k);
      if (valid) {
          setIsAuthenticated(true);
          setKey(k);
          localStorage.setItem('vibelab_admin_key', k);
          loadTools();
      } else {
          alert('Invalid Key');
      }
  };

  const loadTools = async () => {
      setLoading(true);
      try {
          const data = await api.getTools();
          setTools(data);
      } catch (e) {
          console.error(e);
      }
      setLoading(false);
  };

  const handleSave = async (e: React.FormEvent) => {
      e.preventDefault();
      if (!editingTool) return;

      try {
          if (editingTool.id) {
              await api.updateTool(editingTool.id, editingTool, key);
          } else {
              // @ts-ignore
              await api.createTool(editingTool, key);
          }
          setEditingTool(null);
          loadTools();
      } catch (error) {
          alert('Failed to save');
      }
  };

  const handleDelete = async (id: string) => {
      if(!confirm('Are you sure?')) return;
      try {
          await api.deleteTool(id, key);
          loadTools();
      } catch (e) {
          alert('Failed to delete');
      }
  };

  if (!isAuthenticated) {
      return (
          <div className="min-h-screen pt-32 flex justify-center">
              <div className="glass-panel p-8 rounded-2xl w-full max-w-md h-fit">
                  <h2 className="text-2xl font-bold mb-4 dark:text-white">Admin Access</h2>
                  <input 
                    type="password" 
                    placeholder="Enter Admin Key" 
                    className="w-full mb-4 px-4 py-2 rounded-lg bg-slate-50 dark:bg-black/20 border border-slate-200 dark:border-white/10"
                    onKeyDown={(e) => { if (e.key === 'Enter') verify(e.currentTarget.value) }}
                  />
                  <button className="w-full gradient-bg text-white py-2 rounded-lg font-bold">Login</button>
              </div>
          </div>
      );
  }

  return (
    <div className="pt-24 pb-20 px-6 min-h-screen">
        <div className="max-w-7xl mx-auto">
            <div className="flex justify-between items-center mb-8">
                <h1 className="text-3xl font-bold dark:text-white">Admin Dashboard</h1>
                <button 
                    onClick={() => setEditingTool(DEFAULT_TOOL)}
                    className="gradient-bg px-4 py-2 rounded-lg text-white font-bold text-sm"
                >
                    + Add New Tool
                </button>
            </div>

            {/* Editor Modal */}
            {editingTool && (
                <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm">
                    <form onSubmit={handleSave} className="bg-white dark:bg-[#1e293b] w-full max-w-2xl rounded-2xl p-6 max-h-[90vh] overflow-y-auto">
                        <h2 className="text-xl font-bold mb-4 dark:text-white">{editingTool.id ? 'Edit Tool' : 'New Tool'}</h2>

                        <div className="grid grid-cols-2 gap-4 mb-4">
                            <div>
                                <label className="block text-xs font-bold mb-1 dark:text-slate-300">Name</label>
                                <input required value={editingTool.name} onChange={e => setEditingTool({...editingTool, name: e.target.value})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white" />
                            </div>
                            <div>
                                <label className="block text-xs font-bold mb-1 dark:text-slate-300">Website URL</label>
                                <input required value={editingTool.websiteUrl} onChange={e => setEditingTool({...editingTool, websiteUrl: e.target.value})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white" />
                            </div>
                        </div>

                        <div className="grid grid-cols-2 gap-4 mb-4">
                             <div>
                                <label className="block text-xs font-bold mb-1 dark:text-slate-300">Category</label>
                                <select value={editingTool.category} onChange={e => setEditingTool({...editingTool, category: e.target.value as Category})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white">
                                    {Object.values(Category).map(c => <option key={c} value={c}>{c}</option>)}
                                </select>
                            </div>
                            <div>
                                <label className="block text-xs font-bold mb-1 dark:text-slate-300">Pricing</label>
                                <select value={editingTool.pricing} onChange={e => setEditingTool({...editingTool, pricing: e.target.value as any})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white">
                                    <option>Free</option>
                                    <option>Freemium</option>
                                    <option>Paid</option>
                                </select>
                            </div>
                        </div>

                        <div className="mb-4">
                             <label className="block text-xs font-bold mb-1 dark:text-slate-300">Image URL</label>
                             <input value={editingTool.imageUrl} onChange={e => setEditingTool({...editingTool, imageUrl: e.target.value})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white" />
                        </div>

                        <div className="mb-4">
                            <label className="block text-xs font-bold mb-1 dark:text-slate-300">Short Description</label>
                            <input value={editingTool.shortDescription} onChange={e => setEditingTool({...editingTool, shortDescription: e.target.value})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white" />
                        </div>

                        <div className="mb-4">
                            <label className="block text-xs font-bold mb-1 dark:text-slate-300">Full Description</label>
                            <textarea rows={4} value={editingTool.description} onChange={e => setEditingTool({...editingTool, description: e.target.value})} className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white" />
                        </div>

                        <div className="mb-4">
                            <label className="block text-xs font-bold mb-1 dark:text-slate-300">Tags (comma separated)</label>
                            <input 
                                value={editingTool.tags?.join(', ')} 
                                onChange={e => setEditingTool({...editingTool, tags: e.target.value.split(',').map(t => t.trim())})} 
                                className="w-full px-3 py-2 rounded bg-slate-100 dark:bg-black/20 border border-slate-200 dark:border-white/10 dark:text-white" 
                            />
                        </div>

                        <div className="flex items-center gap-4 mb-6">
                            <label className="flex items-center gap-2 dark:text-white text-sm font-bold">
                                <input type="checkbox" checked={editingTool.featured} onChange={e => setEditingTool({...editingTool, featured: e.target.checked})} />
                                Featured
                            </label>
                            <div className="flex items-center gap-2">
                                <label className="text-xs font-bold dark:text-white">Rating</label>
                                <input type="number" step="0.1" value={editingTool.rating} onChange={e => setEditingTool({...editingTool, rating: parseFloat(e.target.value)})} className="w-20 px-2 py-1 rounded bg-slate-100 dark:bg-black/20 dark:text-white" />
                            </div>
                        </div>

                        <div className="flex gap-3 justify-end">
                            <button type="button" onClick={() => setEditingTool(null)} className="px-4 py-2 rounded text-slate-500 hover:bg-slate-100 dark:hover:bg-white/5">Cancel</button>
                            <button type="submit" className="px-6 py-2 rounded gradient-bg text-white font-bold">Save Tool</button>
                        </div>
                    </form>
                </div>
            )}

            {/* List */}
            <div className="glass-panel rounded-2xl overflow-hidden border border-slate-200 dark:border-white/10">
                <table className="w-full text-left text-sm text-slate-600 dark:text-slate-300">
                    <thead className="bg-slate-50 dark:bg-white/5 uppercase font-bold text-xs text-slate-500 dark:text-slate-400">
                        <tr>
                            <th className="px-6 py-4">Tool</th>
                            <th className="px-6 py-4">Category</th>
                            <th className="px-6 py-4">Pricing</th>
                            <th className="px-6 py-4">Featured</th>
                            <th className="px-6 py-4 text-right">Actions</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-200 dark:divide-white/5">
                        {loading ? (
                            <tr><td colSpan={5} className="px-6 py-8 text-center">Loading...</td></tr>
                        ) : tools.map(tool => (
                            <tr key={tool.id} className="hover:bg-slate-50 dark:hover:bg-white/5">
                                <td className="px-6 py-4">
                                    <div className="flex items-center gap-3">
                                        <img src={tool.imageUrl} className="w-8 h-8 rounded object-cover" />
                                        <span className="font-bold dark:text-white">{tool.name}</span>
                                    </div>
                                </td>
                                <td className="px-6 py-4">{tool.category}</td>
                                <td className="px-6 py-4">
                                    <span className={`px-2 py-0.5 rounded text-xs ${tool.pricing === 'Free' ? 'bg-green-100 text-green-700' : 'bg-slate-100 text-slate-700 dark:bg-white/10 dark:text-slate-300'}`}>
                                        {tool.pricing}
                                    </span>
                                </td>
                                <td className="px-6 py-4">
                                    {tool.featured && <span className="text-brand-secondary">★</span>}
                                </td>
                                <td className="px-6 py-4 text-right space-x-2">
                                    <button onClick={() => setEditingTool(tool)} className="text-brand-primary hover:underline">Edit</button>
                                    <button onClick={() => handleDelete(tool.id)} className="text-red-500 hover:underline">Delete</button>
                                </td>
                            </tr>
                        ))}
                    </tbody>
                </table>
            </div>
        </div>
    </div>
  );
};

import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Outlet, useLocation } from 'react-router-dom';
import { Header } from './components/Header';
import { Footer } from './components/Footer';
import { Home } from './pages/Home';
import { ToolDetails } from './pages/ToolDetails';
import { Submit } from './pages/Submit';
import { About } from './pages/About';
import { Admin } from './pages/Admin';

// Layout wrapper to persist Header/Footer
const Layout: React.FC = () => {
  const [isDark, setIsDark] = useState(true);
  const location = useLocation();

  useEffect(() => {
    // Check local storage or system preference
    if (localStorage.theme === 'dark' || (!('theme' in localStorage) && window.matchMedia('(prefers-color-scheme: dark)').matches)) {
      document.documentElement.classList.add('dark');
      setIsDark(true);
    } else {
      document.documentElement.classList.remove('dark');
      setIsDark(false);
    }
  }, []);

  useEffect(() => {
    // Scroll to top on route change
    window.scrollTo(0, 0);
  }, [location.pathname]);

  const toggleTheme = () => {
    const html = document.documentElement;
    if (html.classList.contains('dark')) {
      html.classList.remove('dark');
      localStorage.setItem('theme', 'light');
      setIsDark(false);
    } else {
      html.classList.add('dark');
      localStorage.setItem('theme', 'dark');
      setIsDark(true);
    }
  };

  return (
    <div className="min-h-screen flex flex-col font-sans bg-slate-50 text-slate-900 dark:bg-[#0f172a] dark:text-[#f8fafc] transition-colors duration-300">
      <Header toggleTheme={toggleTheme} isDark={isDark} />
      <main className="flex-1">
        <Outlet />
      </main>
      <Footer />
    </div>
  );
};

function App() {
  return (
    <HashRouter>
      <Routes>
        <Route path="/" element={<Layout />}>
          <Route index element={<Home />} />
          <Route path="tool/:id" element={<ToolDetails />} />
          <Route path="submit" element={<Submit />} />
          <Route path="about" element={<About />} />
          <Route path="admin" element={<Admin />} />
          {/* Fallback for undefined routes */}
          <Route path="*" element={<Home />} />
        </Route>
      </Routes>
    </HashRouter>
  );
}

export default App;

